// FunciГіn para obtener configuraciГіn de avatar por ГЎrea
function getAreaConfig(area) {
    return AREA_AVATARS[area] || AREA_AVATARS['default'];
}

// FunciГіn para generar avatar corporativo
function generateAvatar(user, size = 'md', showBadge = false) {
    const areaConfig = getAreaConfig(user.area);
    const initial = user.displayName.charAt(0).toUpperCase();
    
    const sizes = {
        'sm': { w: 'w-8 h-8', text: 'text-xs', icon: 'text-base' },
        'md': { w: 'w-11 h-11', text: 'text-sm', icon: 'text-xl' },
        'lg': { w: 'w-16 h-16', text: 'text-xl', icon: 'text-3xl' }
    };
    
    const s = sizes[size] || sizes['md'];
    
    return `
        <div class="relative flex-shrink-0">
            <div class="${s.w} bg-gradient-to-br ${areaConfig.gradient} rounded-full flex flex-col items-center justify-center text-white font-bold shadow-lg border-2 border-white">
                <div class="${s.icon} leading-none" style="margin-bottom: -2px;">${areaConfig.icon}</div>
                <div class="${s.text} leading-none font-extrabold">${initial}</div>
            </div>
            ${showBadge && user.area ? `
                <div class="absolute -bottom-1 -right-1 ${size === 'sm' ? 'w-4 h-4 text-[8px]' : 'w-5 h-5 text-[9px]'} rounded-full flex items-center justify-center border-2 border-white shadow-sm" 
                     style="background: ${areaConfig.color};" 
                     title="${escapeHtml(user.area)}">
                    ${areaConfig.emoji}
                </div>
            ` : ''}
        </div>
    `;
}

