// в”Җв”Җ SISTEMA DE ESTADOS (estilo Messenger) в”Җв”Җ
let myStatus = 'available'; // available | away | busy | dnd | invisible
let _manualStatus = false;  // true = el usuario eligiГі el estado manualmente (no sobreescribir con auto-away)

const STATUS_CONFIG = {
    available:  { label: 'Disponible',    color: '#22c55e', dot: 'bg-green-500',  icon: 'рҹҹў' },
    away:       { label: 'Ausente',       color: '#f59e0b', dot: 'bg-yellow-400', icon: 'рҹҹЎ' },
    busy:       { label: 'Ocupado',       color: '#ef4444', dot: 'bg-red-500',    icon: 'рҹ”ҙ' },
    dnd:        { label: 'No molestar',   color: '#7c3aed', dot: 'bg-purple-600', icon: 'рҹ”•' },
    invisible:  { label: 'Invisible',     color: '#6b7280', dot: 'bg-gray-400',   icon: 'вҡ«' },
    offline:    { label: 'Desconectado',  color: '#9ca3af', dot: 'bg-gray-400',   icon: 'вӯ•' },
};

function setMyStatus(newStatus) {
    if (!STATUS_CONFIG[newStatus] || newStatus === 'offline') return;
    myStatus = newStatus;
    _manualStatus = true;
    updatePresence(); // enviar inmediatamente al servidor
    _renderMyStatusBadge();
    _closeStatusMenu();
}

function _renderMyStatusBadge() {
    const badge = document.getElementById('my-status-badge');
    if (!badge) return;
    const cfg = STATUS_CONFIG[myStatus] || STATUS_CONFIG.available;
    badge.style.background = cfg.color;
}

function _openStatusMenu() {
    const menu = document.getElementById('status-menu');
    if (menu) menu.classList.toggle('hidden');
}

function _closeStatusMenu() {
    const menu = document.getElementById('status-menu');
    if (menu) menu.classList.add('hidden');
}

// Cerrar menГә de estado al hacer clic afuera
document.addEventListener('click', (e) => {
    const btn = document.getElementById('status-btn');
    const menu = document.getElementById('status-menu');
    if (menu && btn && !btn.contains(e.target) && !menu.contains(e.target)) {
        menu.classList.add('hidden');
    }
});

// в”Җв”Җ SISTEMA DE ACTIVIDAD Y PRESENCIA INTELIGENTE в”Җв”Җ
let lastActivityTime = Date.now();
const PRESENCE_INTERVAL_ACTIVE = 8000;   // ping cada 8s cuando activo
const PRESENCE_INTERVAL_IDLE   = 30000;  // ping cada 30s cuando idle
const IDLE_THRESHOLD = 5 * 60 * 1000;   // 5 min para considerar idle

function onUserActivity() {
    const now = Date.now();
    const wasIdle = (now - lastActivityTime) > IDLE_THRESHOLD;
    lastActivityTime = now;
    // Si el usuario vuelve de auto-away, restaurar a disponible
    if (wasIdle && myStatus === 'away' && !_manualStatus) {
        myStatus = 'available';
        _renderMyStatusBadge();
    }
    // Si vuelve de idle: ping inmediato + reiniciar intervalos de mensajes (NO el de presencia)
    if (wasIdle && authToken && typeof currentState !== 'undefined' && currentState === AppState.CHAT) {
        updatePresence();
        startPolling();
    }
}

// Detectar actividad: ratГіn, teclado y touch
['mousemove','mousedown','keydown','touchstart','scroll'].forEach(evt =>
    document.addEventListener(evt, onUserActivity, { passive: true })
);

