// RESPONDER MENSAJE
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

function setReplyTo(msgId) {
    // Buscar el mensaje completo en el array
    const msg = messages.find(m => m.id === msgId);
    if (!msg) return;
    const displayName = msg.displayName || msg.username || '';
    const isFile = !!msg.file;
    const text = msg.text || '';
    replyTo = {
        id: msgId,
        displayName: displayName,
        text: isFile ? null : text,
        file: isFile ? true : null
    };

    const container = document.getElementById('replyPreviewContainer');
    if (!container) return;
    container.innerHTML = `
        <div class="flex items-center gap-2 mb-2 px-3 py-2 bg-blue-50 border-l-4 border-blue-500 rounded-lg">
            <div class="flex-1 min-w-0">
                <div class="text-xs font-semibold text-blue-600">вҶ© Respondiendo a ${escapeHtml(displayName)}</div>
                <div class="text-xs text-gray-500 truncate">${isFile ? 'рҹ“Һ Archivo' : escapeHtml(text)}</div>
            </div>
            <button onclick="cancelReply()" class="flex-shrink-0 w-6 h-6 rounded-full bg-gray-200 hover:bg-gray-300 flex items-center justify-center text-gray-500 text-xs transition-colors">вң•</button>
        </div>
    `;
    document.getElementById('msgInput')?.focus();
}

function cancelReply() {
    replyTo = null;
    const container = document.getElementById('replyPreviewContainer');
    if (container) container.innerHTML = '';
}

// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
// MARCAR COMO NO LEГҚDO
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

function markChatAsUnread(username) {
    // Poner al menos 1 no leГӯdo en el contador para que aparezca el badge
    const msgs = messages.filter(m => m.username !== currentUsername);
    const count = msgs.length > 0 ? Math.min(msgs.length, 99) : 1;
    unreadMessages[username] = count;
    // в”Җв”Җ FIX: registrar como "manualmente no leГӯdo" para que el polling NO lo borre в”Җв”Җ
    manuallyUnread.add(username);
    localStorage.setItem('unreadMessages', JSON.stringify(unreadMessages));
    localStorage.setItem('manuallyUnread', JSON.stringify([...manuallyUnread]));
    // Salir del chat activo para que se vea el badge
    selectedUser = null;
    updateTabTitle();
    render();
    // Cerrar el menГә
    const menu = document.getElementById('chatMenu');
    if (menu) menu.classList.add('hidden');
}

