// MENГҡ FLOTANTE GLOBAL вҖ” evita el clipping del overflow-y-auto
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
let _fmTarget = null;

function _getFloatMenu() {
    let el = document.getElementById('_floatMenu');
    if (!el) {
        el = document.createElement('div');
        el.id = '_floatMenu';
        el.style.cssText = 'position:fixed;z-index:99999;display:none;min-width:195px;';
        el.className = 'bg-white border border-gray-200 rounded-xl shadow-2xl overflow-hidden';
        document.body.appendChild(el);
        document.addEventListener('click', function(e) {
            if (e.target.closest('#_floatMenu')) return;
            if (e.target.closest('[data-fm]')) return;
            _closeFloatMenu();
        });
    }
    return el;
}

function _closeFloatMenu() {
    const el = document.getElementById('_floatMenu');
    if (el) el.style.display = 'none';
    _fmTarget = null;
}

function _showFloatMenu(el, btn) {
    el.style.display = 'block';
    const r = btn.getBoundingClientRect();
    const w = 195;
    let left = r.right - w;
    let top = r.bottom + 6;
    if (left < 4) left = 4;
    if (top + 55 > window.innerHeight) top = r.top - 55;
    el.style.left = left + 'px';
    el.style.top = top + 'px';
}

function toggleContactMenu(username, btn) {
    const el = _getFloatMenu();
    if (_fmTarget === 'c_' + username) { _closeFloatMenu(); return; }
    const uc = unreadMessages[username] || 0;
    el.innerHTML = uc > 0
        ? `<button onclick="_closeFloatMenu();markContactAsRead('${username}')" class="w-full px-4 py-3 text-left text-sm text-gray-700 hover:bg-blue-50 flex items-center gap-2 transition-colors">вң… Marcar como leГӯdo</button>`
        : `<button onclick="_closeFloatMenu();markContactAsUnreadFromList('${username}')" class="w-full px-4 py-3 text-left text-sm text-gray-700 hover:bg-blue-50 flex items-center gap-2 transition-colors">рҹ’¬ Marcar como no leГӯdo</button>`;
    _showFloatMenu(el, btn);
    _fmTarget = 'c_' + username;
}

function toggleGroupMenu(groupId, btn) {
    const el = _getFloatMenu();
    if (_fmTarget === 'g_' + groupId) { _closeFloatMenu(); return; }
    const ug = unreadGroupMessages[groupId] || 0;
    el.innerHTML = ug > 0
        ? `<button onclick="_closeFloatMenu();markGroupAsRead('${groupId}')" class="w-full px-4 py-3 text-left text-sm text-gray-700 hover:bg-blue-50 flex items-center gap-2 transition-colors">вң… Marcar como leГӯdo</button>`
        : `<button onclick="_closeFloatMenu();markGroupAsUnreadFromList('${groupId}')" class="w-full px-4 py-3 text-left text-sm text-gray-700 hover:bg-blue-50 flex items-center gap-2 transition-colors">рҹ’¬ Marcar como no leГӯdo</button>`;
    _showFloatMenu(el, btn);
    _fmTarget = 'g_' + groupId;
}

// в”Җв”Җ MARCAR MANUALMENTE вҖ” el polling NO borra estos в”Җв”Җ
function markContactAsUnreadFromList(username) {
    unreadMessages[username] = unreadMessages[username] || 1;
    manuallyUnread.add(username);
    localStorage.setItem('unreadMessages', JSON.stringify(unreadMessages));
    localStorage.setItem('manuallyUnread', JSON.stringify([...manuallyUnread]));
    // в”Җв”Җ FIX: si este chat estГЎ abierto ahora mismo, cerrarlo.
    //    De lo contrario, el timer de loadMessages() llamarГӯa markMessagesAsRead()
    //    y borrarГӯa el badge reciГ©n puesto en ~2.5 segundos.
    if (selectedUser && selectedUser.username === username) {
        selectedUser = null;
    }
    updateTabTitle();
    render();
}

function markContactAsRead(username) {
    delete unreadMessages[username];
    manuallyUnread.delete(username);
    localStorage.setItem('unreadMessages', JSON.stringify(unreadMessages));
    localStorage.setItem('manuallyUnread', JSON.stringify([...manuallyUnread]));
    updateTabTitle();
    render();
}

function markGroupAsUnreadFromList(groupId) {
    unreadGroupMessages[groupId] = unreadGroupMessages[groupId] || 1;
    manuallyUnreadGroups.add(groupId);
    localStorage.setItem('unreadGroupMessages', JSON.stringify(unreadGroupMessages));
    localStorage.setItem('manuallyUnreadGroups', JSON.stringify([...manuallyUnreadGroups]));
    // в”Җв”Җ FIX: si este grupo estГЎ abierto ahora mismo, cerrarlo.
    if (selectedGroup && selectedGroup.id === groupId) {
        selectedGroup = null;
        groupMessages = [];
    }
    updateTabTitle();
    render();
}

function markGroupAsRead(groupId) {
    delete unreadGroupMessages[groupId];
    manuallyUnreadGroups.delete(groupId);
    localStorage.setItem('unreadGroupMessages', JSON.stringify(unreadGroupMessages));
    localStorage.setItem('manuallyUnreadGroups', JSON.stringify([...manuallyUnreadGroups]));
    updateTabTitle();
    render();
}

// Al ABRIR un chat: limpia manuallyUnread + contador
function markMessagesAsRead(username) {
    if (!username) return;
    manuallyUnread.delete(username);
    localStorage.setItem('manuallyUnread', JSON.stringify([...manuallyUnread]));
    if (unreadMessages[username]) {
        delete unreadMessages[username];
        localStorage.setItem('unreadMessages', JSON.stringify(unreadMessages));
    }
    if (messages.length > 0) {
        lastSeenMessages[username] = messages[messages.length - 1].timestamp;
        localStorage.setItem('lastSeenMessages', JSON.stringify(lastSeenMessages));
    }
    updateTabTitle();
}

function markGroupMessagesAsRead(groupId) {
    if (!groupId) return;
    manuallyUnreadGroups.delete(groupId);
    localStorage.setItem('manuallyUnreadGroups', JSON.stringify([...manuallyUnreadGroups]));
    if (unreadGroupMessages[groupId]) {
        delete unreadGroupMessages[groupId];
        localStorage.setItem('unreadGroupMessages', JSON.stringify(unreadGroupMessages));
    }
    if (groupMessages.length > 0) {
        lastSeenGroupMessages[groupId] = groupMessages[groupMessages.length - 1].timestamp;
        localStorage.setItem('lastSeenGroupMessages', JSON.stringify(lastSeenGroupMessages));
    }
    updateTabTitle();
}

// FunciГіn para actualizar los badges de mensajes no leГӯdos (legado, mantenemos por compatibilidad)
function updateUnreadBadges() { updateTabTitle(); }

// FunciГіn para archivar/desarchivar conversaciГіn
function toggleArchiveChat(username) {
    const index = archivedChats.indexOf(username);
    if (index > -1) {
        archivedChats.splice(index, 1);
        showSuccess('ConversaciГіn desarchivada');
    } else {
        archivedChats.push(username);
        showSuccess('ConversaciГіn archivada');
    }
    localStorage.setItem('archivedChats', JSON.stringify(archivedChats));
    
    // Si estamos viendo el chat archivado, salir
    if (selectedUser && selectedUser.username === username) {
        closeCurrentChat();
    }
    
    renderUsersList();
}

function closeCurrentChat() {
    selectedUser = null;
    selectedGroup = null;
    groupMessages = [];
    render();
}

// FunciГіn para mostrar/ocultar el selector de emojis
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
// EMOJI PICKER - SISTEMA FLOTANTE CON CATEGORГҚAS Y BГҡSQUEDA
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
function _getEmojiPicker() {
    let el = document.getElementById('_emojiPickerFloat');
    if (!el) {
        el = document.createElement('div');
        el.id = '_emojiPickerFloat';
        el.style.cssText = 'position:fixed;z-index:99999;display:none;width:340px;max-height:400px;';
        el.className = 'bg-white border border-gray-200 rounded-2xl shadow-2xl overflow-hidden flex flex-col';
        document.body.appendChild(el);

        // Cerrar al click fuera
        document.addEventListener('click', function(e) {
            if (e.target.closest('#_emojiPickerFloat')) return;
            if (e.target.closest('button[data-emoji-btn]')) return;
            _hideEmojiPicker();
        });
    }
    return el;
}

function _hideEmojiPicker() {
    const el = document.getElementById('_emojiPickerFloat');
    if (el) el.style.display = 'none';
}

function _renderEmojiPickerContent() {
    const el = _getEmojiPicker();
    const cat = EMOJI_CATEGORIES.find(c => c.id === _emojiActiveCat) || EMOJI_CATEGORIES[0];
    const term = _emojiSearchTerm.toLowerCase();
    const list = term
        ? EMOJI_CATEGORIES.flatMap(c => c.emojis).filter(e => e.includes(term))
        : cat.emojis;

    const tabsHtml = EMOJI_CATEGORIES.map(c => `
        <button onclick="_emojiActiveCat='${c.id}';_emojiSearchTerm='';_renderEmojiPickerContent();"
            title="${c.label}"
            style="font-size:18px;padding:5px 7px;border-radius:8px;transition:background .15s;${_emojiActiveCat===c.id?'background:#e3f2fd;':'background:transparent;'}"
            class="hover:bg-blue-50">${c.icon}</button>
    `).join('');

    const gridHtml = list.length
        ? list.map(e => `<button onclick="insertEmoji('${e}')" style="font-size:22px;padding:4px;border-radius:8px;line-height:1;" class="hover:bg-gray-100 transition">${e}</button>`).join('')
        : `<div style="grid-column:1/-1;color:#9ca3af;text-align:center;padding:24px;">Sin resultados</div>`;

    el.innerHTML = `
        <div style="padding:10px 10px 6px;border-bottom:1px solid #f3f4f6;">
            <div style="display:flex;gap:2px;flex-wrap:wrap;margin-bottom:8px;">${tabsHtml}</div>
            <input id="_emojiSearch" type="text" placeholder="рҹ”Қ Buscar emoji..." value="${_emojiSearchTerm}"
                style="width:100%;padding:6px 10px;border:1px solid #e5e7eb;border-radius:10px;font-size:13px;outline:none;"
                oninput="_emojiSearchTerm=this.value;_renderEmojiPickerContent();">
        </div>
        <div style="display:grid;grid-template-columns:repeat(8,1fr);gap:2px;padding:8px;overflow-y:auto;max-height:280px;">
            ${gridHtml}
        </div>
        <div style="padding:4px 10px 6px;border-top:1px solid #f3f4f6;font-size:11px;color:#9ca3af;text-align:center;">
            ${term ? list.length + ' resultados' : cat.label + ' В· ' + list.length + ' emojis'}
        </div>
    `;
}

function toggleEmojiPicker(btnEl) {
    // btnEl puede llegar como referencia o buscamos por data-emoji-btn
    const el = _getEmojiPicker();
    if (el.style.display !== 'none') {
        _hideEmojiPicker();
        return;
    }
    // Posicionar encima del botГіn рҹҳҖ
    const btn = btnEl || document.querySelector('button[data-emoji-btn]');
    if (btn) {
        const r = btn.getBoundingClientRect();
        const pickerH = 400;
        const pickerW = 340;
        let top = r.top - pickerH - 8;
        let left = r.left - pickerW + r.width;
        if (top < 8) top = r.bottom + 8;
        if (left < 8) left = 8;
        if (left + pickerW > window.innerWidth - 8) left = window.innerWidth - pickerW - 8;
        el.style.top = top + 'px';
        el.style.left = left + 'px';
    }
    _renderEmojiPickerContent();
    el.style.display = 'flex';
    // Focus al buscador
    setTimeout(() => { const s = document.getElementById('_emojiSearch'); if(s) s.focus(); }, 50);
}

// FunciГіn para insertar emoji en el input
function insertEmoji(emoji) {
    const input = document.getElementById('msgInput');
    if (input) {
        const start = input.selectionStart;
        const end = input.selectionEnd;
        const text = input.value;
        input.value = text.substring(0, start) + emoji + text.substring(end);
        input.selectionStart = input.selectionEnd = start + emoji.length;
        input.focus();
    }
    // El picker permanece abierto para seguir insertando emojis
}

// FunciГіn para mostrar/ocultar menГә del chat
function toggleChatMenu(event) {
    event.stopPropagation();
    const menu = document.getElementById('chatMenu');
    if (menu) {
        menu.classList.toggle('hidden');
    }
}

// FunciГіn auxiliar para escapar HTML (prevenir XSS)
function escapeHtml(text) {
    const map = {
        '&': '&amp;',
        '<': '&lt;',
        '>': '&gt;',
        '"': '&quot;',
        "'": '&#039;'
    };
    return text.replace(/[&<>"']/g, m => map[m]);
}

// FunciГіn auxiliar para mostrar mensajes de error
function showError(message) {
    const errorDiv = document.createElement('div');
    errorDiv.className = 'fixed top-4 right-4 bg-red-100 border border-red-400 text-red-700 px-4 py-3 rounded shadow-lg z-50 max-w-md fade-in';
    errorDiv.innerHTML = `
        <div class="flex items-center gap-2">
            <span class="text-2xl">вқҢ</span>
            <span>${escapeHtml(message)}</span>
        </div>
    `;
    document.body.appendChild(errorDiv);
    setTimeout(() => errorDiv.remove(), 5000);
}

// FunciГіn auxiliar para mostrar mensajes de Г©xito
function showSuccess(message) {
    const successDiv = document.createElement('div');
    successDiv.className = 'fixed top-4 right-4 bg-green-100 border border-green-400 text-green-700 px-4 py-3 rounded shadow-lg z-50 max-w-md fade-in';
    successDiv.innerHTML = `
        <div class="flex items-center gap-2">
            <span class="text-2xl">вң…</span>
            <span>${escapeHtml(message)}</span>
        </div>
    `;
    document.body.appendChild(successDiv);
    setTimeout(() => successDiv.remove(), 3000);
}

function clearAllIntervals() {
    // presenceInterval es independiente вҖ” se cancela SOLO en logout via clearPresenceInterval()
    if (usersInterval)         { clearInterval(usersInterval);         usersInterval = null; }
    if (messagesInterval)      { clearInterval(messagesInterval);      messagesInterval = null; }
    if (groupMessagesInterval) { clearInterval(groupMessagesInterval); groupMessagesInterval = null; }
}
function clearPresenceInterval() {
    if (presenceInterval) { clearInterval(presenceInterval); presenceInterval = null; }
}

// ============================================
// AUTENTICACIГ“N
// ============================================

async function verifyToken() {
    if (isVerifying || !authToken) {
        return false;
    }
    
    isVerifying = true;
    
    try {
        const response = await fetch('/api/verify', {
            method: 'GET',
            headers: {
                'Authorization': `Bearer ${authToken}`,
                'Content-Type': 'application/json'
            }
        });
        
        if (response.ok) {
            const data = await response.json();
            if (data.success) {
                currentUsername = data.username;
                currentDisplayName = data.displayName;
                isAdmin = data.isAdmin || false;
                console.log('вң… Token vГЎlido:', currentUsername, isAdmin ? '[ADMIN]' : '');
                isVerifying = false;
                return true;
            }
        }
        
        // Token invГЎlido o expirado
        console.log('вқҢ Token invГЎlido o expirado');
        authToken = null;
        localStorage.removeItem('chatAuthToken');
        isVerifying = false;
        return false;
        
    } catch (error) {
        console.error('Error verificando token:', error);
        isVerifying = false;
        return false;
    }
}

async function register() {
    const username = document.getElementById('regUsername').value.trim();
    const displayName = document.getElementById('regDisplayName').value.trim();
    const password = document.getElementById('regPassword').value;
    const confirmPassword = document.getElementById('regConfirmPassword').value;
    
    // Validaciones en cliente
    if (!username || !password) {
        showError('Usuario y contraseГұa son requeridos');
        return;
    }
    
    if (username.length < 3) {
        showError('El usuario debe tener al menos 3 caracteres');
        return;
    }
    
    if (password.length < 4) {
        showError('La contraseГұa debe tener al menos 4 caracteres');
        return;
    }
    
    if (password !== confirmPassword) {
        showError('Las contraseГұas no coinciden');
        return;
    }
    
    try {
        const response = await fetch('/api/register', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                username,
                password,
                displayName: displayName || username
            })
        });
        
        const data = await response.json();
        
        if (response.ok && data.success) {
            showSuccess('ВЎCuenta creada exitosamente! Ahora puedes iniciar sesiГіn');
            setTimeout(() => {
                currentState = AppState.LOGIN;
                render();
            }, 1500);
        } else {
            showError(data.error || 'Error al crear la cuenta');
        }
    } catch (error) {
        console.error('Error en registro:', error);
        showError('Error de conexiГіn con el servidor');
    }
}

async function login() {
    const username = document.getElementById('loginUsername').value.trim();
    const password = document.getElementById('loginPassword').value;
    
    if (!username || !password) {
        showError('Usuario y contraseГұa son requeridos');
        return;
    }
    
    try {
        const response = await fetch('/api/login', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ username, password })
        });
        
        const data = await response.json();
        
        if (response.ok && data.success) {
            authToken = data.token;
            currentUsername = data.username;
            currentDisplayName = data.displayName;
            isAdmin = data.isAdmin || false;
            
            localStorage.setItem('chatAuthToken', authToken);
            
            showSuccess(`ВЎBienvenido ${currentDisplayName}!`);
            
            currentState = AppState.CHAT;
            render();
            
            // Iniciar sesiГіn de chat
            startChatSession();
        } else {
            showError(data.error || 'Error al iniciar sesiГіn');
        }
    } catch (error) {
        console.error('Error en login:', error);
        showError('Error de conexiГіn con el servidor');
    }
}

async function logout() {
    try {
        // Limpiar todos los intervalos, incluyendo el heartbeat de presencia
        clearAllIntervals();
        clearPresenceInterval();
        
        if (authToken) {
            await fetch('/api/logout', {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${authToken}`,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({ token: authToken })
            });
        }
        
        authToken = null;
        currentUsername = null;
        currentDisplayName = null;
        selectedUser = null;
        activeUsers = [];
        messages = [];
        myStatus = 'available';
        _manualStatus = false;
        
        localStorage.removeItem('chatAuthToken');
        
        currentState = AppState.LOGIN;
        render();
        
        showSuccess('SesiГіn cerrada exitosamente');
    } catch (error) {
        console.error('Error en logout:', error);
        // Aun con error, forzar cierre de sesiГіn local
        authToken = null;
        localStorage.removeItem('chatAuthToken');
        currentState = AppState.LOGIN;
        render();
    }
}

// ============================================
// FUNCIONES DE CHAT
// ============================================

// Determina si el usuario estГЎ activo en este momento
function isUserActive() {
    return (Date.now() - lastActivityTime) < IDLE_THRESHOLD;
}

// Inicia (o reinicia) todos los intervalos de polling con velocidades adaptativas
function startPolling() {
    clearAllIntervals();

    const usersMs = isUserActive() ? 8000 : 20000;  // lista de usuarios/grupos
    const msgsMs     = isUserActive() ? 2500  : 8000;   // mensajes del chat activo

    // presenceInterval corre en su propio heartbeat, no aquГӯ
    usersInterval = setInterval(async () => {
        await loadContacts();
        await loadUsers();
        loadGroups();
        checkUnreadGroupMessages();
    }, usersMs);
    messagesInterval      = setInterval(() => { if (selectedUser)  loadMessages(); }, msgsMs);
    groupMessagesInterval = setInterval(() => {
        if (selectedGroup) loadGroupMessages();
        else checkUnreadGroupMessages();
    }, msgsMs);
}

function startPresenceHeartbeat() {
    if (presenceInterval) return; // ya corre, no duplicar
    presenceInterval = setInterval(async () => {
        if (!authToken) return;
        const isIdle = (Date.now() - lastActivityTime) > IDLE_THRESHOLD;
        if (isIdle && myStatus === 'available' && !_manualStatus) {
            myStatus = 'away'; _renderMyStatusBadge();
        } else if (!isIdle && myStatus === 'away' && !_manualStatus) {
            myStatus = 'available'; _renderMyStatusBadge();
        }
        await updatePresence();
    }, 20000); // cada 20s, NUNCA se reinicia
}

function startChatSession() {
    if ('Notification' in window && Notification.permission === 'default') {
        Notification.requestPermission();
    }
    loadUsers();
    loadContacts();
    loadGroups();
    updatePresence();
    startPresenceHeartbeat();
    startPolling();
}

document.addEventListener('visibilitychange', () => {
    if (document.visibilityState === 'visible' && authToken && currentState === AppState.CHAT) {
        // Al volver a la pestaГұa: presencia inmediata + reiniciar polling con velocidad activa
        lastActivityTime = Date.now();
        updatePresence();
        loadUsers();
        loadContacts();
        loadGroups();
        if (selectedUser) loadMessages();
        if (selectedGroup) loadGroupMessages();
        else checkUnreadGroupMessages();
        updateTabTitle();
        startPolling();
        startPresenceHeartbeat(); // asegurarse de que siga corriendo (no duplica si ya corre)
    } else if (document.visibilityState === 'hidden') {
        startPolling(); // reducir velocidad de mensajes, el heartbeat sigue intacto
        updateTabTitle();
    }
});

let _presenceFailCount = 0;
let _reconnectingShown = false;

function _showReconnecting(show) {
    let indicator = document.getElementById('reconnect-indicator');
    if (show && !indicator) {
        indicator = document.createElement('div');
        indicator.id = 'reconnect-indicator';
        indicator.style.cssText = 'position:fixed;bottom:16px;left:50%;transform:translateX(-50%);background:#f59e0b;color:#fff;padding:6px 16px;border-radius:20px;font-size:13px;z-index:9999;box-shadow:0 2px 8px rgba(0,0,0,0.2)';
        indicator.textContent = 'вҡ пёҸ Sin conexiГіn вҖ” reconectando...';
        document.body.appendChild(indicator);
        _reconnectingShown = true;
    } else if (!show && indicator) {
        indicator.remove();
        _reconnectingShown = false;
    }
}

async function updatePresence() {
    if (!authToken) return;
    try {
        const res = await fetch('/api/presence', {
            method: 'POST',
            headers: {
                'Authorization': `Bearer ${authToken}`,
                'Content-Type': 'application/json'
            },
            body: JSON.stringify({ token: authToken, status: myStatus })
        });
        _presenceFailCount = 0;
        _showReconnecting(false);

        if (res.status === 401) {
            console.warn('Token expirado, redirigiendo al login...');
            logout();
        }
    } catch (error) {
        // Error de red вҖ” NUNCA cerrar sesiГіn por esto
        _presenceFailCount++;
        console.warn(`Presencia: error de red (intento ${_presenceFailCount})`, error.message);
        if (_presenceFailCount >= 3) _showReconnecting(true);
    }
}

async function loadUsers() {
    if (!authToken) return;
    
    try {
        const response = await fetch('/api/users', {
            headers: {
                'Authorization': `Bearer ${authToken}`,
                'Content-Type': 'application/json'
            }
        });
        
        if (!response.ok) {
            if (response.status === 401) {
                console.log('Token invГЎlido, cerrando sesiГіn...');
                logout();
                return;
            }
            throw new Error(`HTTP error! status: ${response.status}`);
        }
        
        const data = await response.json();
        activeUsers = data.users.filter(u => u.username !== currentUsername);
        
        // Verificar mensajes no leГӯdos para cada usuario
        await checkUnreadMessagesForAllUsers();
        
        renderUsersList();
        
    } catch (error) {
        console.error('Error cargando usuarios:', error);
    }
}

async function loadContacts() {
    if (!authToken) return;
    try {
        const response = await fetch('/api/contacts', {
            headers: {
                'Authorization': `Bearer ${authToken}`,
                'Content-Type': 'application/json'
            }
        });
        if (!response.ok) {
            if (response.status === 401) { logout(); return; }
            return;
        }
        const data = await response.json();
        if (data.success) {
            contacts = data.contacts;
            await checkUnreadMessagesForAllUsers();
            renderUsersList();
        }
    } catch (error) {
        console.error('Error cargando contactos:', error);
    }
}

async function loadGroups() {
    if (!authToken) return;
    try {
        const response = await fetch('/api/groups', {
            headers: { 'Authorization': `Bearer ${authToken}` }
        });
        if (!response.ok) { if (response.status === 401) { logout(); return; } return; }
        const data = await response.json();
        if (data.success) {
            groups = data.groups;

            // Limpiar datos de grupos eliminados del localStorage
            const activeGroupIds = new Set(groups.map(g => g.id));
            let changed = false;
            Object.keys(unreadGroupMessages).forEach(id => {
                if (!activeGroupIds.has(id)) { delete unreadGroupMessages[id]; changed = true; }
            });
            if (changed) localStorage.setItem('unreadGroupMessages', JSON.stringify(unreadGroupMessages));

            Object.keys(lastSeenGroupMessages).forEach(id => {
                if (!activeGroupIds.has(id)) delete lastSeenGroupMessages[id];
            });
            localStorage.setItem('lastSeenGroupMessages', JSON.stringify(lastSeenGroupMessages));

            Object.keys(lastContactMessage).forEach(key => {
                if (key.startsWith('g_') && !activeGroupIds.has(key.slice(2))) delete lastContactMessage[key];
            });
            localStorage.setItem('lastContactMessage', JSON.stringify(lastContactMessage));

            // Si el grupo seleccionado fue eliminado, cerrarlo automГЎticamente
            if (selectedGroup && !activeGroupIds.has(selectedGroup.id)) {
                selectedGroup = null;
                groupMessages = [];
                render(); // re-render completo para salir del chat eliminado
                showError('El grupo fue eliminado por el administrador');
                return;
            }

            renderUsersList();
        }
    } catch (error) {
        console.error('Error cargando grupos:', error);
    }
}

async function loadGroupMessages() {
    if (!authToken || !selectedGroup) return;
    try {
        const response = await fetch(`/api/groups/${selectedGroup.id}/messages`, {
            headers: { 'Authorization': `Bearer ${authToken}` }
        });
        if (!response.ok) { if (response.status === 401) { logout(); return; } return; }
        const data = await response.json();
        if (data.success) {
            const oldCount = groupMessages.length;
            groupMessages = data.messages || [];
            // Actualizar Гәltimo mensaje del grupo activo
            if (groupMessages.length > 0) {
                const last = groupMessages[groupMessages.length - 1];
                lastContactMessage['g_' + selectedGroup.id] = {
                    timestamp: last.timestamp,
                    text: last.text || (last.file ? 'рҹ“Һ Archivo' : ''),
                    senderName: last.displayName
                };
                localStorage.setItem('lastContactMessage', JSON.stringify(lastContactMessage));
            }
            // Actualizar info del grupo (puede haber cambiado miembros)
            if (data.group) {
                selectedGroup = { ...selectedGroup, ...data.group };
            }
            if (groupMessages.length > oldCount) {
                const newOnes = groupMessages.slice(oldCount);
                const newFromOthers = newOnes.filter(m => m.username !== currentUsername);
                if (newFromOthers.length > 0) {
                    // Sonido inmediato (ya estamos en el grupo abierto)
                    playGroupNotificationSound();
                }
            }
            renderGroupMessages();
            markGroupMessagesAsRead(selectedGroup.id);
        }
    } catch (error) {
        console.error('Error cargando mensajes del grupo:', error);
    }
}

// Verificar mensajes no leГӯdos de todos los contactos
async function checkUnreadMessagesForAllUsers() {
    if (!authToken) return;

    const allUsersToCheck = [
        ...activeUsers,
        ...contacts.filter(c => !activeUsers.some(a => a.username === c.username))
    ].filter(user => !(selectedUser && selectedUser.username === user.username));

    await Promise.all(allUsersToCheck.map(async (user) => {
        try {
            const response = await fetch(`/api/messages/${user.username}`, {
                headers: { 'Authorization': `Bearer ${authToken}`, 'Content-Type': 'application/json' }
            });
            if (!response.ok) return;

            const data = await response.json();
            const userMessages = data.messages || [];
            const lastSeen = lastSeenMessages[user.username] || 0;

            // Guardar el Гәltimo mensaje del contacto para ordenar y mostrar hora
            if (userMessages.length > 0) {
                const last = userMessages[userMessages.length - 1];
                lastContactMessage[user.username] = {
                    timestamp: last.timestamp,
                    text: last.text || (last.file ? 'рҹ“Һ Archivo' : ''),
                    senderName: last.displayName
                };
                localStorage.setItem('lastContactMessage', JSON.stringify(lastContactMessage));
            }

            const newMsgs = userMessages.filter(m => m.timestamp > lastSeen && m.username !== currentUsername);

            if (newMsgs.length > 0) {
                const prevCount = unreadMessages[user.username] || 0;
                unreadMessages[user.username] = newMsgs.length;
                localStorage.setItem('unreadMessages', JSON.stringify(unreadMessages));

                // Solo notificar mensajes realmente nuevos (no notificados antes)
                const brandNew = newMsgs.filter(m => !notifiedTimestamps.has(m.timestamp));
                if (brandNew.length > 0) {
                    brandNew.forEach(msg => notifiedTimestamps.add(msg.timestamp));
                    // Guardar solo los Гәltimos 500 para no crecer infinito
                    const arr = Array.from(notifiedTimestamps).slice(-500);
                    localStorage.setItem('notifiedTimestamps', JSON.stringify(arr));

                    const lastMsg = brandNew[brandNew.length - 1];
                    const preview = brandNew.length > 1
                        ? `${brandNew.length} mensajes nuevos`
                        : (lastMsg.text || 'рҹ“Һ Archivo adjunto');

                    fireNotification({
                        senderName: user.displayName,
                        senderInitial: user.displayName.charAt(0).toUpperCase(),
                        text: preview,
                        color: '#6366f1',
                        isGroup: false,
                        tag: `dm_${user.username}`,
                        onClick: () => {
                            sidebarTab = 'contacts';
                            selectUser(user.username, user.displayName);
                        }
                    });
                }
                updateTabTitle();
            } else {
                // Solo borrar si NO fue marcado manualmente
                if (unreadMessages[user.username] && !manuallyUnread.has(user.username)) {
                    delete unreadMessages[user.username];
                    localStorage.setItem('unreadMessages', JSON.stringify(unreadMessages));
                    updateTabTitle();
                }
            }
        } catch (error) {
            console.error(`Error verificando mensajes de ${user.username}:`, error);
        }
    }));
}

// Verificar mensajes no leГӯdos en todos los grupos
async function checkUnreadGroupMessages() {
    if (!authToken || groups.length === 0) return;

    await Promise.all(groups.map(async (group) => {
        if (selectedGroup && selectedGroup.id === group.id) return;
        try {
            const response = await fetch(`/api/groups/${group.id}/messages`, {
                headers: { 'Authorization': `Bearer ${authToken}` }
            });
            if (!response.ok) return;

            const data = await response.json();
            const msgs = data.messages || [];
            const lastSeen = lastSeenGroupMessages[group.id] || 0;

            // Guardar el Гәltimo mensaje del grupo para ordenar y mostrar hora
            if (msgs.length > 0) {
                const last = msgs[msgs.length - 1];
                lastContactMessage['g_' + group.id] = {
                    timestamp: last.timestamp,
                    text: last.text || (last.file ? 'рҹ“Һ Archivo' : ''),
                    senderName: last.displayName
                };
                localStorage.setItem('lastContactMessage', JSON.stringify(lastContactMessage));
            }

            const newMsgs = msgs.filter(m => m.timestamp > lastSeen && m.username !== currentUsername);

            if (newMsgs.length > 0) {
                unreadGroupMessages[group.id] = newMsgs.length;
                localStorage.setItem('unreadGroupMessages', JSON.stringify(unreadGroupMessages));

                const brandNew = newMsgs.filter(m => !notifiedTimestamps.has(`g_${m.timestamp}_${m.username}`));
                if (brandNew.length > 0) {
                    brandNew.forEach(m => notifiedTimestamps.add(`g_${m.timestamp}_${m.username}`));
                    const arr = Array.from(notifiedTimestamps).slice(-500);
                    localStorage.setItem('notifiedTimestamps', JSON.stringify(arr));

                    const lastMsg = brandNew[brandNew.length - 1];
                    const preview = brandNew.length > 1
                        ? `${brandNew.length} mensajes en ${group.name}`
                        : (lastMsg.text || 'рҹ“Һ Archivo adjunto');
                    const color = stringToColor(group.id);

                    fireNotification({
                        senderName: `${lastMsg.displayName} В· ${group.name}`,
                        senderInitial: group.name.charAt(0).toUpperCase(),
                        text: preview,
                        color,
                        isGroup: true,
                        tag: `group_${group.id}`,
                        onClick: () => {
                            sidebarTab = 'groups';
                            selectGroup(group.id);
                        }
                    });
                }
                updateTabTitle();
            } else {
                // Solo borrar si NO fue marcado manualmente
                if (unreadGroupMessages[group.id] && !manuallyUnreadGroups.has(group.id)) {
                    delete unreadGroupMessages[group.id];
                    localStorage.setItem('unreadGroupMessages', JSON.stringify(unreadGroupMessages));
                    updateTabTitle();
                }
            }
        } catch(e) {
            console.error(`Error verificando grupo ${group.name}:`, e);
        }
    }));
}

