                <button data-fm onclick="event.stopPropagation(); toggleContactMenu('${user.username}', this)"
                    class="w-7 h-7 rounded-full hover:bg-gray-200 flex items-center justify-center text-gray-400 hover:text-gray-600 transition-colors text-lg leading-none"
                    title="Opciones">вӢ®</button>
