async function sendMessage() {
    const input = document.getElementById('msgInput');
    if (!input) return;
    const text = input.value.trim();
    if (!text && !attachedFile) return;

    // Redirigir al grupo si estГЎ activo
    if (selectedGroup) {
        await sendGroupMessage();
        return;
    }
    
    if (!authToken || !selectedUser) {
        showError('No se puede enviar el mensaje');
        return;
    }
    
    const messageData = { to: selectedUser.username, text, file: attachedFile, replyTo: replyTo };
    
    try {
        const response = await fetch('/api/send', {
            method: 'POST',
            headers: { 'Authorization': `Bearer ${authToken}`, 'Content-Type': 'application/json' },
            body: JSON.stringify(messageData)
        });
        if (!response.ok) {
            if (response.status === 401) { logout(); return; }
            throw new Error(`HTTP error! status: ${response.status}`);
        }
        const data = await response.json();
        if (data.success) {
            input.value = '';
            attachedFile = null;
            replyTo = null;
            document.getElementById('filePreviewContainer').innerHTML = '';
            const rpc = document.getElementById('replyPreviewContainer');
            if (rpc) rpc.innerHTML = '';
            loadMessages();
        } else {
            showError(data.error || 'Error al enviar mensaje');
        }
    } catch (error) {
        console.error('Error enviando mensaje:', error);
        showError('Error de conexiГіn al enviar mensaje');
    }
}

async function sendGroupMessage() {
    const input = document.getElementById('msgInput');
    if (!input || !selectedGroup) return;
    const text = input.value.trim();
    if (!text && !attachedFile) return;

    try {
        const response = await fetch(`/api/groups/${selectedGroup.id}/send`, {
            method: 'POST',
            headers: { 'Authorization': `Bearer ${authToken}`, 'Content-Type': 'application/json' },
            body: JSON.stringify({ text, file: attachedFile })
        });
        if (!response.ok) {
            if (response.status === 401) { logout(); return; }
            throw new Error(`HTTP error! status: ${response.status}`);
        }
        const data = await response.json();
        if (data.success) {
            input.value = '';
            attachedFile = null;
            const fp = document.getElementById('filePreviewContainer');
            if (fp) fp.innerHTML = '';
            loadGroupMessages();
        } else {
            showError(data.error || 'Error al enviar mensaje al grupo');
        }
    } catch (error) {
        showError('Error de conexiГіn al enviar mensaje');
    }
}

