async function adminSubmitChangePassword(username) {
    const newPassword = document.getElementById('modalNewPassword')?.value;
    const confirmPassword = document.getElementById('modalConfirmPassword')?.value;

    if (!newPassword || newPassword.length < 4) {
        showError('La contraseГұa debe tener al menos 4 caracteres');
        return;
    }
    if (newPassword !== confirmPassword) {
        showError('Las contraseГұas no coinciden');
        return;
    }

    try {
        const response = await fetch('/api/admin/change-password', {
            method: 'POST',
            headers: {
                'Authorization': `Bearer ${authToken}`,
                'Content-Type': 'application/json'
            },
            body: JSON.stringify({ username, newPassword })
        });
        const data = await response.json();
        if (data.success) {
            showSuccess(data.message || 'ContraseГұa actualizada');
            closeAdminModal();
        } else {
            showError(data.error || 'Error al cambiar la contraseГұa');
        }
    } catch (e) {
        showError('Error de conexiГіn');
    }
}

async function adminCreateUser() {
    const username = document.getElementById('createUsername')?.value.trim();
    const displayName = document.getElementById('createDisplayName')?.value.trim();
    const area = document.getElementById('createArea')?.value.trim() || '';
    const password = document.getElementById('createPassword')?.value;
    const confirmPassword = document.getElementById('createConfirmPassword')?.value;

    if (!username || !password) {
        showError('Usuario y contraseГұa son requeridos');
        return;
    }
    if (username.length < 3) {
        showError('El usuario debe tener al menos 3 caracteres');
        return;
    }
    if (password.length < 4) {
        showError('La contraseГұa debe tener al menos 4 caracteres');
        return;
    }
    if (password !== confirmPassword) {
        showError('Las contraseГұas no coinciden');
        return;
    }

    try {
        const response = await fetch('/api/admin/create-user', {
            method: 'POST',
            headers: {
                'Authorization': `Bearer ${authToken}`,
                'Content-Type': 'application/json'
            },
            body: JSON.stringify({ username, displayName: displayName || username, area, password })
        });
        const data = await response.json();
        if (data.success) {
            showSuccess(data.message || 'Usuario creado exitosamente');
            document.getElementById('createUsername').value = '';
            document.getElementById('createDisplayName').value = '';
            if (document.getElementById('createArea')) document.getElementById('createArea').value = '';
            document.getElementById('createPassword').value = '';
            document.getElementById('createConfirmPassword').value = '';
            await loadAdminUsers();
            switchAdminTab('users');
        } else {
            showError(data.error || 'Error al crear el usuario');
        }
    } catch (e) {
        showError('Error de conexiГіn');
    }
}

async function adminDeleteUser(username, displayName) {
    if (!confirm(`ВҝEstГЎs seguro de eliminar al usuario "${displayName}" (@${username})?\n\nEsta acciГіn no se puede deshacer.`)) return;

    try {
        const response = await fetch('/api/admin/delete-user', {
            method: 'POST',
            headers: {
                'Authorization': `Bearer ${authToken}`,
                'Content-Type': 'application/json'
            },
            body: JSON.stringify({ username })
        });
        const data = await response.json();
        if (data.success) {
            showSuccess(data.message || 'Usuario eliminado');
            await loadAdminUsers();
        } else {
            showError(data.error || 'Error al eliminar usuario');
        }
    } catch (e) {
        showError('Error de conexiГіn');
    }
}

async function adminToggleAdmin(username, displayName, currentlyAdmin) {
    const action = currentlyAdmin ? 'revocar' : 'asignar';
    const actionPast = currentlyAdmin ? 'revocado' : 'otorgado';
    const emoji = currentlyAdmin ? 'в¬ҮпёҸ' : 'в¬ҶпёҸ';
    const confirmMsg = currentlyAdmin
        ? `ВҝQuitar el rol de administrador a ${displayName}?\n\nEl usuario perderГЎ acceso al panel de administraciГіn.`
        : `ВҝAsignar rol de administrador a ${displayName}?\n\nEl usuario podrГЎ administrar usuarios y grupos.`;

    if (!confirm(`${emoji} ${confirmMsg}`)) return;

    try {
        const response = await fetch('/api/admin/set-admin', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${authToken}`
            },
            body: JSON.stringify({ username, grant: !currentlyAdmin })
        });
        const data = await response.json();
        if (data.success) {
            showSuccess(data.message || `Rol de administrador ${actionPast} para ${displayName}`);
            await loadAdminUsers();
        } else {
            showError(data.error || `Error al ${action} administrador`);
        }
    } catch (e) {
        showError('Error de conexiГіn');
    }
}

