// CAMBIAR CONTRASEГ‘A PROPIA
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

function openChangePasswordModal() {
    const modal = document.getElementById('changePasswordModal');
    if (!modal) return;
    // Limpiar campos
    ['cpCurrentPassword', 'cpNewPassword', 'cpConfirmPassword'].forEach(id => {
        const el = document.getElementById(id);
        if (el) el.value = '';
    });
    const err = document.getElementById('cpError');
    if (err) { err.textContent = ''; err.classList.add('hidden'); }
    const bar = document.getElementById('cpStrengthBar');
    const lbl = document.getElementById('cpStrengthLabel');
    if (bar) bar.classList.add('hidden');
    if (lbl) lbl.classList.add('hidden');
    modal.classList.remove('hidden');
    setTimeout(() => document.getElementById('cpCurrentPassword')?.focus(), 100);
}

function closeChangePasswordModal() {
    const modal = document.getElementById('changePasswordModal');
    if (modal) modal.classList.add('hidden');
}

function toggleCpVisibility(inputId, btn) {
    const input = document.getElementById(inputId);
    if (!input) return;
    if (input.type === 'password') {
        input.type = 'text';
        btn.textContent = 'рҹҷҲ';
    } else {
        input.type = 'password';
        btn.textContent = 'рҹ‘ҒпёҸ';
    }
}

function checkCpStrength(value) {
    const bar = document.getElementById('cpStrengthBar');
    const fill = document.getElementById('cpStrengthFill');
    const lbl = document.getElementById('cpStrengthLabel');
    if (!bar || !fill || !lbl) return;

    if (!value) { bar.classList.add('hidden'); lbl.classList.add('hidden'); return; }
    bar.classList.remove('hidden');
    lbl.classList.remove('hidden');

    let score = 0;
    if (value.length >= 6) score++;
    if (value.length >= 10) score++;
    if (/[A-Z]/.test(value)) score++;
    if (/[0-9]/.test(value)) score++;
    if (/[^A-Za-z0-9]/.test(value)) score++;

    const levels = [
        { pct: '20%', color: '#ef4444', label: 'Muy dГ©bil' },
        { pct: '40%', color: '#f97316', label: 'DГ©bil' },
        { pct: '60%', color: '#eab308', label: 'Regular' },
        { pct: '80%', color: '#22c55e', label: 'Fuerte' },
        { pct: '100%', color: '#16a34a', label: 'рҹ’Ә Muy fuerte' },
    ];
    const level = levels[Math.min(score, 4)];
    fill.style.width = level.pct;
    fill.style.background = level.color;
    lbl.textContent = level.label;
    lbl.style.color = level.color;
}

async function submitChangePassword() {
    const currentPassword = document.getElementById('cpCurrentPassword')?.value.trim();
    const newPassword     = document.getElementById('cpNewPassword')?.value.trim();
    const confirmPassword = document.getElementById('cpConfirmPassword')?.value.trim();
    const errEl           = document.getElementById('cpError');
    const submitBtn       = document.getElementById('cpSubmitBtn');

    const showCpError = (msg) => {
        if (!errEl) return;
        errEl.textContent = msg;
        errEl.classList.remove('hidden');
    };
    const hideCpError = () => errEl?.classList.add('hidden');

    hideCpError();

    if (!currentPassword) return showCpError('Ingresa tu contraseГұa actual');
    if (!newPassword)      return showCpError('Ingresa la nueva contraseГұa');
    if (newPassword.length < 4) return showCpError('La nueva contraseГұa debe tener al menos 4 caracteres');
    if (newPassword !== confirmPassword) return showCpError('Las contraseГұas nuevas no coinciden');
    if (currentPassword === newPassword) return showCpError('La nueva contraseГұa debe ser diferente a la actual');

    submitBtn.disabled = true;
    submitBtn.textContent = 'GuardandoвҖҰ';

    try {
        const response = await fetch('/api/change-password', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${authToken}`
            },
            body: JSON.stringify({ currentPassword, newPassword })
        });
        const data = await response.json();

        if (data.success) {
            closeChangePasswordModal();
            showSuccess('рҹ”‘ ContraseГұa actualizada correctamente');
        } else {
            showCpError(data.error || 'Error al cambiar la contraseГұa');
        }
    } catch (e) {
        showCpError('Error de conexiГіn. Intenta de nuevo.');
    } finally {
        submitBtn.disabled = false;
        submitBtn.textContent = 'Guardar';
    }
}

function switchAdminTab(tab) {
    adminTab = tab;
    const tabs = ['users', 'create', 'groups'];
    tabs.forEach(t => {
        const btn = document.getElementById(`tabAdmin_${t}`);
        const content = document.getElementById(`contentAdmin_${t}`);
        if (!btn || !content) return;
        if (t === tab) {
            btn.className = 'flex-1 py-3 text-sm font-semibold text-blue-600 border-b-2 border-blue-600 transition-colors';
            content.classList.remove('hidden');
        } else {
            btn.className = 'flex-1 py-3 text-sm font-semibold text-gray-500 hover:text-gray-700 border-b-2 border-transparent transition-colors';
            content.classList.add('hidden');
        }
    });
    if (tab === 'groups') loadAdminGroups();
}

// =============================================
// ADMIN вҖ” FUNCIONES DE GRUPOS
// =============================================

let adminGroups = [];
let groupSearchFilter = '';
let expandedGroups = new Set();

async function loadAdminGroups() {
    const container = document.getElementById('adminGroupsContainer');
    if (container) container.innerHTML = `<div class="text-center py-8 text-gray-400"><div class="text-3xl mb-2">вҸі</div><p class="text-sm">Cargando grupos...</p></div>`;
    try {
        const response = await fetch('/api/admin/groups', {
            headers: { 'Authorization': `Bearer ${authToken}` }
        });
        const data = await response.json();
        if (data.success) {
            adminGroups = data.groups;
            renderAdminGroups();
            const statGroups = document.getElementById('statTotalGroups');
            if (statGroups) statGroups.textContent = adminGroups.length;
        }
    } catch(e) { showError('Error cargando grupos'); }
}

function renderAdminGroups() {
    const container = document.getElementById('adminGroupsContainer');
    if (!container) return;

    const filter = groupSearchFilter.toLowerCase();
    const filtered = adminGroups.filter(g =>
        g.name.toLowerCase().includes(filter) ||
        (g.description || '').toLowerCase().includes(filter) ||
        g.members.some(m => m.toLowerCase().includes(filter))
    );

    // Update counter label
    const countLabel = document.getElementById('groupCountLabel');
    if (countLabel) {
        countLabel.textContent = filter
            ? `${filtered.length} de ${adminGroups.length} grupos`
            : `${adminGroups.length} grupo${adminGroups.length !== 1 ? 's' : ''} en total`;
    }

    if (adminGroups.length === 0) {
        container.innerHTML = `
            <div class="text-center py-12 text-gray-400">
                <div class="text-5xl mb-3">рҹҸў</div>
                <p class="text-sm font-medium">No hay grupos creados aГәn.</p>
                <p class="text-xs mt-1">Usa el formulario de arriba para crear el primero.</p>
            </div>`;
        return;
    }

    if (filtered.length === 0) {
        container.innerHTML = `
            <div class="text-center py-8 text-gray-400">
                <div class="text-4xl mb-2">рҹ”Қ</div>
                <p class="text-sm">No hay grupos que coincidan con "<strong>${escapeHtml(groupSearchFilter)}</strong>"</p>
            </div>`;
        return;
    }

    container.innerHTML = filtered.map(group => {
        const color = stringToColor(group.id);
        const isExpanded = expandedGroups.has(group.id);
        const nonMembers = adminUsers.filter(u => !group.members.includes(u.username));
        const createdDate = group.createdAt ? new Date(group.createdAt * 1000).toLocaleDateString('es-CO', {day:'2-digit',month:'short',year:'numeric'}) : 'вҖ”';
        const safeGroupName = escapeHtml(group.name).replace(/'/g, '&#39;');

        return `
        <div class="bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden">
            <!-- Header del grupo -->
            <div class="flex items-center gap-3 p-4 cursor-pointer hover:bg-gray-50 transition-colors select-none"
                 onclick="toggleGroupExpand('${group.id}')">
                <div class="w-11 h-11 rounded-xl flex items-center justify-center text-white text-lg font-bold flex-shrink-0 shadow-sm"
                     style="background:${color}">
                    ${group.name.charAt(0).toUpperCase()}
                </div>
                <div class="flex-1 min-w-0">
                    <div class="font-semibold text-gray-900 text-sm">${escapeHtml(group.name)}</div>
                    <div class="text-xs text-gray-400 flex items-center gap-2 mt-0.5">
                        <span>рҹ‘Ҙ ${group.memberCount} miembro${group.memberCount !== 1 ? 's' : ''}</span>
                        ${group.description ? `<span>В·</span><span class="truncate max-w-xs italic">${escapeHtml(group.description)}</span>` : ''}
                    </div>
                </div>
                <div class="flex items-center gap-1 flex-shrink-0">
                    <span class="text-xs text-gray-300 mr-1">${isExpanded ? 'в–І' : 'в–ј'}</span>
                    <button onclick="event.stopPropagation(); adminDeleteGroup('${group.id}', '${safeGroupName}')"
                        class="p-1.5 text-red-400 hover:bg-red-50 rounded-lg transition-colors text-base" title="Eliminar grupo">рҹ—‘пёҸ</button>
                </div>
            </div>

            ${isExpanded ? `
            <div class="border-t border-gray-100 bg-gray-50/50">

                <!-- Editar nombre y descripciГіn -->
                <div class="p-4 border-b border-gray-100">
                    <div class="text-xs font-semibold text-gray-500 uppercase tracking-wider mb-3">вңҸпёҸ Editar grupo</div>
                    <div class="flex gap-2 mb-2">
                        <input id="rename_${group.id}" type="text" value="${escapeHtml(group.name)}"
                            class="flex-1 text-sm px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                            placeholder="Nombre del grupo">
                        <button onclick="adminRenameGroup('${group.id}')"
                            class="px-3 py-2 bg-blue-600 hover:bg-blue-700 text-white text-xs rounded-lg transition-colors font-semibold whitespace-nowrap">
                            Renombrar
                        </button>
                    </div>
                    <div class="flex gap-2">
                        <input id="desc_${group.id}" type="text" value="${escapeHtml(group.description || '')}"
                            class="flex-1 text-sm px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                            placeholder="DescripciГіn (opcional)">
                        <button onclick="adminUpdateGroupDesc('${group.id}')"
                            class="px-3 py-2 bg-gray-500 hover:bg-gray-600 text-white text-xs rounded-lg transition-colors font-semibold whitespace-nowrap">
                            Guardar
                        </button>
                    </div>
                </div>

                <!-- Lista de miembros -->
                <div class="p-4 border-b border-gray-100">
                    <div class="flex items-center justify-between mb-3">
                        <div class="text-xs font-semibold text-gray-500 uppercase tracking-wider">рҹ‘Ҙ Miembros (${group.memberCount})</div>
                        ${nonMembers.length > 0 ? `
                        <button onclick="adminAddAllToGroup('${group.id}')"
                            class="text-xs text-indigo-600 hover:text-indigo-800 font-medium transition-colors">вһ• Agregar todos</button>` :
                        `<span class="text-xs text-green-600 font-medium">вң… Todos los usuarios</span>`}
                    </div>
                    <div class="flex flex-wrap gap-1.5 max-h-44 overflow-y-auto pr-1">
                        ${group.members.map(u => {
                            const found = adminUsers.find(au => au.username === u);
                            const name = found ? found.displayName : u;
                            const isOnline = typeof activeUsers !== 'undefined' && Array.isArray(activeUsers) && activeUsers.some(a => a.username === u);
                            return `<span class="flex items-center gap-1 bg-white border border-gray-200 rounded-full px-2.5 py-1 text-xs text-gray-700 shadow-sm">
                                <span class="w-1.5 h-1.5 rounded-full flex-shrink-0 ${isOnline ? 'bg-green-400' : 'bg-gray-300'}"></span>
                                <span class="font-medium">${escapeHtml(name)}</span>
                                <span class="text-gray-400 text-xs">@${escapeHtml(u)}</span>
                                <button onclick="adminRemoveMember('${group.id}', '${u}')"
                                    class="text-gray-300 hover:text-red-500 ml-0.5 font-bold text-sm leading-none transition-colors" title="Quitar">Г—</button>
                            </span>`;
                        }).join('')}
                    </div>
                </div>

                ${nonMembers.length > 0 ? `
                <!-- Agregar miembro -->
                <div class="p-4">
                    <div class="text-xs font-semibold text-gray-500 uppercase tracking-wider mb-3">вһ• Agregar miembro</div>
                    <div class="flex gap-2">
                        <select id="addMember_${group.id}"
                            class="flex-1 text-sm px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 bg-white">
                            <option value="">Seleccionar usuario...</option>
                            ${nonMembers.map(u => `<option value="${u.username}">${escapeHtml(u.displayName)} В· @${u.username}</option>`).join('')}
                        </select>
                        <button onclick="adminAddMember('${group.id}')"
                            class="px-4 py-2 bg-green-600 hover:bg-green-700 text-white text-sm rounded-lg transition-colors font-semibold">
                            Agregar
                        </button>
                    </div>
                </div>` : `
                <div class="px-4 py-3 text-center">
                    <p class="text-xs text-gray-400">Todos los usuarios ya son miembros de este grupo</p>
                </div>`}

                <!-- Footer con info -->
                <div class="px-4 py-2 bg-gray-100/60 border-t border-gray-100 text-xs text-gray-400 flex flex-wrap items-center gap-4">
                    <span>рҹ“… Creado: ${createdDate}</span>
                    <span>рҹҶ” <code class="font-mono bg-white px-1 rounded">${group.id}</code></span>
                    <span>рҹ‘Ө Por: ${escapeHtml(group.createdBy || 'вҖ”')}</span>
                </div>
            </div>` : ''}
        </div>`;
    }).join('');
}

function toggleGroupExpand(groupId) {
    if (expandedGroups.has(groupId)) {
        expandedGroups.delete(groupId);
    } else {
        expandedGroups.add(groupId);
    }
    renderAdminGroups();
}

async function adminRenameGroup(groupId) {
    const input = document.getElementById(`rename_${groupId}`);
    const name = input?.value.trim();
    if (!name) { showError('El nombre no puede estar vacГӯo'); return; }
    try {
        const response = await fetch('/api/admin/groups/rename', {
            method: 'POST',
            headers: { 'Authorization': `Bearer ${authToken}`, 'Content-Type': 'application/json' },
            body: JSON.stringify({ groupId, name })
        });
        const data = await response.json();
        if (data.success) { showSuccess(data.message); await loadAdminGroups(); await loadGroups(); }
        else showError(data.error);
    } catch(e) { showError('Error de conexiГіn'); }
}

async function adminUpdateGroupDesc(groupId) {
    const input = document.getElementById(`desc_${groupId}`);
    const description = input?.value.trim() || '';
    try {
        const response = await fetch('/api/admin/groups/update-description', {
            method: 'POST',
            headers: { 'Authorization': `Bearer ${authToken}`, 'Content-Type': 'application/json' },
            body: JSON.stringify({ groupId, description })
        });
        const data = await response.json();
        if (data.success) { showSuccess(data.message); await loadAdminGroups(); }
        else showError(data.error);
    } catch(e) { showError('Error de conexiГіn'); }
}

async function adminAddAllToGroup(groupId) {
    if (!confirm('ВҝAgregar a TODOS los usuarios registrados a este grupo?')) return;
    try {
        const response = await fetch('/api/admin/groups/add-all', {
            method: 'POST',
            headers: { 'Authorization': `Bearer ${authToken}`, 'Content-Type': 'application/json' },
            body: JSON.stringify({ groupId })
        });
        const data = await response.json();
        if (data.success) { showSuccess(data.message); await loadAdminGroups(); await loadGroups(); }
        else showError(data.error);
    } catch(e) { showError('Error de conexiГіn'); }
}

async function adminAddMember(groupId) {
    const sel = document.getElementById(`addMember_${groupId}`);
    if (!sel || !sel.value) { showError('Selecciona un usuario'); return; }
    const username = sel.value;
    try {
        const response = await fetch('/api/admin/groups/add-member', {
            method: 'POST',
            headers: { 'Authorization': `Bearer ${authToken}`, 'Content-Type': 'application/json' },
            body: JSON.stringify({ groupId, username })
        });
        const data = await response.json();
        if (data.success) { showSuccess(data.message); await loadAdminGroups(); await loadGroups(); }
        else showError(data.error);
    } catch(e) { showError('Error de conexiГіn'); }
}

async function adminRemoveMember(groupId, username) {
    try {
        const response = await fetch('/api/admin/groups/remove-member', {
            method: 'POST',
            headers: { 'Authorization': `Bearer ${authToken}`, 'Content-Type': 'application/json' },
            body: JSON.stringify({ groupId, username })
        });
        const data = await response.json();
        if (data.success) { showSuccess(data.message); await loadAdminGroups(); await loadGroups(); }
        else showError(data.error);
    } catch(e) { showError('Error de conexiГіn'); }
}

async function adminDeleteGroup(groupId, groupName) {
    if (!confirm(`ВҝEliminar el grupo "${groupName}"?\nSe borrarГЎn tambiГ©n todos los mensajes del grupo.`)) return;
    try {
        const response = await fetch('/api/admin/groups/delete', {
            method: 'POST',
            headers: { 'Authorization': `Bearer ${authToken}`, 'Content-Type': 'application/json' },
            body: JSON.stringify({ groupId })
        });
        const data = await response.json();
        if (data.success) {
            showSuccess(data.message);
            expandedGroups.delete(groupId);
            if (selectedGroup && selectedGroup.id === groupId) closeCurrentChat();
            await loadAdminGroups();
            await loadGroups();
        } else showError(data.error);
    } catch(e) { showError('Error de conexiГіn'); }
}

async function adminCreateGroup() {
    const name = document.getElementById('newGroupName')?.value.trim();
    const description = document.getElementById('newGroupDesc')?.value.trim();
    const addAll = document.getElementById('newGroupAddAll')?.checked;
    if (!name) { showError('El nombre del grupo es requerido'); return; }
    try {
        const response = await fetch('/api/admin/groups/create', {
            method: 'POST',
            headers: { 'Authorization': `Bearer ${authToken}`, 'Content-Type': 'application/json' },
            body: JSON.stringify({ name, description, addAllUsers: addAll })
        });
        const data = await response.json();
        if (data.success) {
            showSuccess(data.message);
            document.getElementById('newGroupName').value = '';
            document.getElementById('newGroupDesc').value = '';
            expandedGroups.add(data.groupId || '');
            await loadAdminGroups();
            await loadGroups();
        } else showError(data.error);
    } catch(e) { showError('Error de conexiГіn'); }
}

